<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  html,body{
    margin:0;
    height:100%;
    background:#111;
    color:#ddd;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;
    flex-direction:column;
    align-items:center;
    justify-content:center;
  }
  #controls{
    margin-bottom:10px;
    display:flex;
    gap:6px;
    flex-wrap:wrap;
    justify-content:center;
  }
  button{
    background:#333;
    border:none;
    color:#ddd;
    padding:6px 12px;
    cursor:pointer;
    border-radius:4px;
    min-width:70px;
  }
  button.active{
    background:#555;
  }
  button:hover{
    background:#444;
  }
  canvas{
    background:#000;
    image-rendering:pixelated;
    border:2px solid #555;
  }
</style>
</head>
<body>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand" width="400" height="400"></canvas>

<script>
(() => {
  // ----- constants -----
  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  const names = ["empty","sand","water","wall","acid"];
  const ids = {empty:EMPTY,sand:SAND,water:WATER,wall:WALL,acid:ACID};

  // ----- grid -----
  const w = 80, h = 80;
  const grid = new Uint8Array(w*h);
  const colors = [
    [0,0,0],          // empty
    [194,178,128],    // sand
    [64,164,223],     // water
    [100,100,100],    // wall
    [0,255,0]         // acid
  ];

  // ----- canvas -----
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const offCanvas = document.createElement('canvas');
  offCanvas.width = w; offCanvas.height = h;
  const offCtx = offCanvas.getContext('2d');
  const cellSize = canvas.width / w;

  // ----- UI -----
  let selected = SAND;
  const btnMap = {
    "mat-sand":SAND,
    "mat-water":WATER,
    "mat-wall":WALL,
    "mat-acid":ACID,
    "mat-empty":EMPTY
  };
  for (const id in btnMap){
    const b=document.getElementById(id);
    b.addEventListener('click',()=>{selected=btnMap[id];updateActive();});
  }
  document.getElementById('clear').addEventListener('click',()=>{clearGrid();});
  function updateActive(){
    for(const id in btnMap){
      const b=document.getElementById(id);
      b.classList.toggle('active',selected===btnMap[id]);
    }
  }
  updateActive();

  // ----- painting -----
  let painting = false;
  canvas.addEventListener('mousedown',e=>{painting=true;paint(e);});
  canvas.addEventListener('mousemove',e=>{if(painting)paint(e);});
  window.addEventListener('mouseup',()=>{painting=false;});
  function paint(e){
    const rect = canvas.getBoundingClientRect();
    const cx = Math.floor((e.clientX-rect.left)/cellSize);
    const cy = Math.floor((e.clientY-rect.top)/cellSize);
    if(cx>=0&&cx<w&&cy>=0&&cy<h){
      setCell(cx,cy,selected);
      draw();
    }
  }

  // ----- grid helpers -----
  function idx(x,y){return y*w+x;}
  function getCell(x,y){return grid[idx(x,y)];}
  function setCell(x,y,val){grid[idx(x,y)]=val;}
  function clearGrid(){grid.fill(EMPTY); draw();}

  // ----- simulation step -----
  function step(){
    for(let y=h-1;y>=0;y--){
      for(let x=0;x<w;x++){
        const i = idx(x,y);
        const mat = grid[i];
        if(mat===SAND){
          if(moveIf(x,y,0,1,true,SAND)) continue;
          const dirs = Math.random()<0.5?[[-1,1],[1,1]]:[[1,1],[-1,1]];
          for(const d of dirs){
            if(moveIf(x,y,d[0],d[1],true,SAND)) break;
          }
        }else if(mat===WATER){
          if(moveIf(x,y,0,1,true,WATER)) continue;
          const dirs = Math.random()<0.5?[[-1,1],[1,1]]:[[1,1],[-1,1]];
          let moved=false;
          for(const d of dirs){
            if(moveIf(x,y,d[0],d[1],true,WATER)){moved=true;break;}
          }
          if(!moved){
            const hdirs = Math.random()<0.5?[[-1,0],[1,0]]:[[1,0],[-1,0]];
            for(const d of hdirs){
              if(moveIf(x,y,d[0],0,false,WATER)) break;
            }
          }
        }else if(mat===ACID){
          if(moveIf(x,y,0,1,true,ACID)){}
          else{
            const dirs = Math.random()<0.5?[[-1,1],[1,1]]:[[1,1],[-1,1]];
            let moved=false;
            for(const d of dirs){
              if(moveIf(x,y,d[0],d[1],true,ACID)){moved=true;break;}
            }
            if(!moved){
              const hdirs = Math.random()<0.5?[[-1,0],[1,0]]:[[1,0],[-1,0]];
              for(const d of hdirs){
                if(moveIf(x,y,d[0],0,false,ACID)) break;
              }
            }
          }
          // dissolve
          const dissolve = [[0,1],[-1,0],[1,0],[-1,1],[1,1]];
          for(const d of dissolve){
            const nx=x+d[0], ny=y+d[1];
            if(nx<0||nx>=w||ny<0||ny>=h) continue;
            const nIdx=idx(nx,ny);
            const nMat=grid[nIdx];
            if(nMat===SAND||nMat===WALL) grid[nIdx]=EMPTY;
          }
        }
      }
    }
  }

  function moveIf(x,y,dx,dy,allowSwap,mat){
    const nx=x+dx, ny=y+dy;
    if(nx<0||nx>=w||ny<0||ny>=h) return false;
    const target = grid[idx(nx,ny)];
    if(target===EMPTY){
      grid[idx(nx,ny)]=mat;
      grid[idx(x,y)]=EMPTY;
      return true;
    }
    if(allowSwap && (target===WATER||target===ACID)){
      grid[idx(nx,ny)]=mat;
      grid[idx(x,y)]=target;
      return true;
    }
    return false;
  }

  // ----- rendering -----
  function draw(){
    const img = offCtx.createImageData(w,h);
    const data = img.data;
    for(let i=0;i<grid.length;i++){
      const col = colors[grid[i]];
      const p = i*4;
      data[p]=col[0];
      data[p+1]=col[1];
      data[p+2]=col[2];
      data[p+3]=255;
    }
    offCtx.putImageData(img,0,0);
    ctx.imageSmoothingEnabled=false;
    ctx.clearRect(0,0,canvas.width,canvas.height);
    ctx.drawImage(offCanvas,0,0,canvas.width,canvas.height);
  }

  // ----- animation loop -----
  function loop(){
    step();
    draw();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

  // ----- API -----
  window.sim = {
    w, h,
    tick(n){
      for(let i=0;i<n;i++) step();
      draw();
    },
    get(x,y){
      if(x<0||x>=w||y<0||y>=h) return null;
      return names[grid[idx(x,y)]];
    },
    set(x,y,material){
      if(x<0||x>=w||y<0||y>=h) return;
      const v = ids[material];
      if(v!==undefined){
        grid[idx(x,y)]=v;
        draw();
      }
    },
    clear(){
      clearGrid();
    }
  };
})();
</script>
</body>
</html>
